const fs = require('fs');
const path = require('path');

function readFile(filename) {
  const allowedExtensions = ['.txt', '.jpg', '.png'];
  const extension = path.extname(filename);
  if (!allowedExtensions.includes(extension)) {
    throw new Error(`Invalid file type: ${extension}`);
  }

  return fs.readFileSync(path.join(__dirname, 'uploads', filename), 'utf8');
}
```
In this example, we only allow files with specific extensions.

